// Processar resultados e montar alertas WhatsApp
const items = $input.all();
const alertas = [];

for (const item of items) {
  const data = item.json.data || item.json;

  // Estoque Crítico
  if (data.produtos_criticos && data.produtos_criticos.length > 0) {
    const prods = data.produtos_criticos.slice(0, 10);
    let msg = '⚠️ *ALERTA: Estoque Crítico*\n\n';
    msg += `📊 *${data.total_criticos || prods.length} produto(s) abaixo do mínimo:*\n\n`;
    prods.forEach((p, i) => {
      msg += `${i+1}. *${p.nome || p.descricao}*\n`;
      msg += `   📦 Atual: ${p.estoque_atual} | Mínimo: ${p.estoque_minimo}\n`;
    });
    if (data.total_criticos > 10) msg += `\n... e mais ${data.total_criticos - 10} produtos\n`;
    msg += '\n_n8n Automação - ALUFORCE_';
    alertas.push({ tipo: 'estoque_critico', mensagem: msg, prioridade: 'alta', destino: 'PCP,COMPRAS' });
  }

  // Contas Vencidas
  if (data.contas_vencidas && data.contas_vencidas.length > 0) {
    const contas = data.contas_vencidas.slice(0, 8);
    let msg = '🚨 *CONTAS VENCIDAS*\n\n';
    msg += `💰 *${data.total_vencidas || contas.length} conta(s) em atraso:*\n\n`;
    contas.forEach((c, i) => {
      msg += `${i+1}. ${c.cliente_fornecedor || c.descricao}\n`;
      msg += `   💵 R$ ${c.valor} | ⏰ ${c.dias_atraso || '?'} dias\n`;
    });
    msg += '\n_n8n Automação - ALUFORCE_';
    alertas.push({ tipo: 'conta_vencida', mensagem: msg, prioridade: 'alta', destino: 'FINANCEIRO' });
  }

  // Contas a Vencer (próximos 3 dias)
  if (data.contas_vencer && data.contas_vencer.length > 0) {
    const contas = data.contas_vencer.slice(0, 5);
    let msg = '💳 *Contas a Vencer (próximos 3 dias)*\n\n';
    contas.forEach((c, i) => {
      msg += `${i+1}. ${c.cliente_fornecedor || c.descricao}\n`;
      msg += `   💵 R$ ${c.valor} | 📅 ${c.vencimento}\n`;
    });
    msg += '\n_n8n Automação - ALUFORCE_';
    alertas.push({ tipo: 'conta_vencer', mensagem: msg, prioridade: 'normal', destino: 'FINANCEIRO' });
  }

  // Pedidos Atrasados
  if (data.pedidos_atrasados && data.pedidos_atrasados.length > 0) {
    const peds = data.pedidos_atrasados.slice(0, 8);
    let msg = '🚨 *PEDIDOS DE COMPRA ATRASADOS*\n\n';
    msg += `📋 *${data.total_atrasados || peds.length} pedido(s) atrasados:*\n\n`;
    peds.forEach((p, i) => {
      msg += `${i+1}. Pedido *#${p.numero || p.id}*\n`;
      msg += `   🏢 ${p.fornecedor} | ⏰ ${p.dias_atraso || '?'} dias\n`;
    });
    msg += '\n_n8n Automação - ALUFORCE_';
    alertas.push({ tipo: 'pedido_atrasado', mensagem: msg, prioridade: 'alta', destino: 'COMPRAS' });
  }
}

// Se não há alertas, registrar que tudo ok
if (alertas.length === 0) {
  alertas.push({ tipo: 'tudo_ok', mensagem: null, prioridade: 'none', destino: 'none' });
}

return alertas.map(a => ({ json: a }));
